def apply_patch(document, operations):
    result = dict(document)
    for op in operations:
        path = op['path'].lstrip('/')
        kind = op['op']
        if kind in {'add', 'replace'}:
            result[path] = op['value']
        elif kind == 'remove':
            result.pop(path, None)
        else:
            raise ValueError(f'unsupported op: {kind}')
    return result

