class JsonPatchTests(unittest.TestCase):
    def test_applies_top_level_operations(self):
        original = {'a': 1, 'b': 2}
        patched = apply_patch(original, [
            {'op': 'replace', 'path': '/a', 'value': 3},
            {'op': 'add', 'path': '/c', 'value': 4},
            {'op': 'remove', 'path': '/b'},
        ])
        self.assertEqual(patched, {'a': 3, 'c': 4})
        self.assertEqual(original, {'a': 1, 'b': 2})


